# 1. Load necessary libraries
library(tidyr)
library(magrittr)
library(tidyverse)
library(janitor)
library(RColorBrewer)
library(ggplot2)
library(dplyr)

# 2. Load the CSV file
# Ensure the file name matches the one generated by your Python script
df_pub <- read.csv("publication_dates_summary.csv") %>% 
  as_tibble()

# 3. Data Cleaning
# Convert year to numeric and filter out invalid/N/A entries
df_clean <- df_pub %>%
  mutate(publication_year = as.numeric(as.character(publication_year))) %>%
  filter(!is.na(publication_year)) %>%
  # Optional: Filter for recent history if there are outliers
  filter(publication_year > 1990)

# --- ANALYSIS 1: TOTAL MODELS PER YEAR (GLOBAL) ---
stats_year <- df_clean %>%
  count(publication_year)

print("Total publications per year:")
print(stats_year)

plot_timeline_global <- ggplot(stats_year, aes(x = publication_year, y = n)) +
  geom_line(color = "#2E86C1", linewidth = 1) +  # Changed size to linewidth
  geom_point(color = "#1B4F72", size = 2) +      # size is still correct for points
  scale_x_continuous(breaks = seq(min(df_clean$publication_year, na.rm = TRUE), 2025, by = 2)) +
  labs(
    title = "Evolution of BioModels Publications (Global)",
    subtitle = "Number of infectious disease models published per year",
    x = "Year of Publication",
    y = "Number of Models"
  ) +
  theme_minimal()

# --- ANALYSIS 2: TRENDS BY DISEASE CATEGORY ---
stats_disease_year <- df_clean %>%
  group_by(publication_year, disease_category) %>%
  summarise(count = n(), .groups = "drop")

plot_timeline_disease <- ggplot(stats_disease_year, aes(x = publication_year, y = count, color = disease_category)) +
  geom_line(size = 1) +
  geom_point() +
  scale_x_continuous(breaks = seq(min(df_clean$publication_year), 2025, by = 2)) +
  labs(
    title = "Publication Trends by Disease Category",
    subtitle = "Comparative growth of modeling research over time",
    x = "Year",
    y = "Number of Models",
    color = "Disease"
  ) +
  theme_light() +
  theme(legend.position = "bottom")

# --- ANALYSIS 3: TOP JOURNALS ---
plot_journals <- df_clean %>%
  count(journal) %>%
  filter(journal != "N/A" & journal != "") %>%
  top_n(10, n) %>%
  ggplot(aes(x = reorder(journal, n), y = n)) +
  geom_col(fill = "#82E0AA") +
  coord_flip() +
  labs(
    title = "Top 10 Journals Publishing These Models",
    x = "Journal Name",
    y = "Number of Models"
  ) +
  theme_minimal()

# --- DISPLAY OUTPUTS ---
print(plot_timeline_global)
print(plot_timeline_disease)
print(plot_journals)

